class Solution {
public:
    string smallestSubsequence(string s) {
        int n = s.size();
        vector<int> last(26);
        for (int i = 0; i < n; i++) {
            last[s[i] - 'a'] = i;
        }
        vector<bool> visited(26, false);
        string res;
        for (int i = 0; i < n; i++) {
            int idx = s[i] - 'a';
            if (visited[idx]) continue;
            while (!res.empty() && res.back() > s[i] && last[res.back() - 'a'] > i) {
                visited[res.back() - 'a'] = false;
                res.pop_back();
            }
            res.push_back(s[i]);
            visited[idx] = true;
        }
        return res;
    }
};

